typedef enum {S0, S1, S2, S3, S4, S5} state_t;
state_t state = S0;
always_ff @(posedge clk) begin
  unique case (state)
    S0: begin
      if (up) state <= S1;
      if (down) state <= S5;
    end
    S1: begin
      if (up) state <= S2;
      if (down) state <= S0;
    end
    // ... other states
  endcase
end

typedef enum bit [2:0] {S0=3'b000, S1=3'b001, S2=3'b010, S3=3'b011, S4=3'b100, S5=3'b101} state_t;
state_t state;
initial state = S0;
always_ff @(posedge clk) begin
  if (rst) state <= S0;
  else begin
    unique case (1'b1)
      state == S0: begin
        if (up) state <= S1;
        if (down) state <= S5;
      end
    endcase
  end
end
